        const htmlData = `
            <html>
                <body>
                    <a href="https://example.com/page1">Page 1</a>
                    <a href="/relative/path">Relative Link</a>
                    <a href="mailto:test@example.com">Email</a>
                    <a href="javascript:void(0)">JS Link</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        assert(Array.isArray(result), 'Result should be an array');
        assert(result.length >= 2, 'Should extract at least 2 valid links');

        // Check that mailto and javascript links are filtered out
        const urls = result.map(item => item.url);
        assert(!urls.some(url => url.includes('mailto:')), 'Should filter out mailto links');
        assert(!urls.some(url => url.includes('javascript:')), 'Should filter out javascript links');

        done();
    });

    it('should handle relative URLs with base URL', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="/about">About</a>
                    <a href="contact.html">Contact</a>
                    <a href="../parent">Parent</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com/subdir/';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        assert(result.length > 0, 'Should extract relative links');
        result.forEach(item => {
            assert(typeof item.url === 'string', 'URL should be a string');
            assert(typeof item.text === 'string', 'Text should be a string');
            assert(typeof item.type !== 'undefined', 'Type should be defined');
        });

        done();
    });

    it('should respect HTML base tag', function(done) {
        const htmlData = `
            <html>
                <head>
                    <base href="https://different.com/">
                </head>
                <body>
                    <a href="page.html">Test Page</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        assert(result.length > 0, 'Should extract links');
        // The base tag should affect URL resolution
        const extractedUrl = result[0].url;
        assert(extractedUrl.includes('different.com'), 'Should use base tag for URL resolution');

        done();
    });

    it('should handle duplicate URLs by combining text', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="https://example.com/same">First Text</a>
                    <a href="https://example.com/same">Second Text</a>
                    <a href="https://example.com/different">Different Link</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        // Should have 2 unique URLs (same URL should be deduplicated)
        const sameUrlItems = result.filter(item => item.url === 'https://example.com/same');
        assert(sameUrlItems.length === 1, 'Duplicate URLs should be merged');

        if (sameUrlItems.length > 0) {
            const combinedText = sameUrlItems[0].text;
            assert(combinedText.includes('First Text'), 'Should include first text');
            assert(combinedText.includes('Second Text'), 'Should include second text');
        }

        done();
    });

    it('should filter out invalid and short URLs', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="">Empty</a>
                    <a href="ab">Too Short</a>
                    <a href="ftp://example.com">FTP Link</a>
                    <a href="https://valid.com">Valid Link</a>
                    <a>No href</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        // Should only have the valid link
        assert(result.length >= 1, 'Should extract valid links');

        const urls = result.map(item => item.url);
        assert(!urls.some(url => url.startsWith('ftp:')), 'Should filter out FTP links');
        assert(!urls.some(url => url.length < 3), 'Should filter out short URLs');

        done();
    });

    it('should exclude the source URL from results', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="https://example.com">Self Link</a>
                    <a href="https://example.com/other">Other Page</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        const urls = result.map(item => item.url);
        assert(!urls.includes(sourceUrl), 'Should exclude the source URL from results');

        done();
    });
});
